const raw = $input.first().json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '';
const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

let audit = { score: 5, issue: '', fix: '' };
try { audit = JSON.parse(cleaned); }
catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { try { audit = JSON.parse(match[0]); } catch(e2) {} }
}

const ctx = $('Parse Content Response').first().json;

return [{ json: {
  ...ctx,
  audit_score: Number(audit.score) || 5,
  audit_issue: audit.issue || '',
  audit_fix: audit.fix || ''
}}];

const bbResponse = $input.first().json;
const imageUrl = bbResponse.image_url_png || bbResponse.image_url || '';

const ctx = $('Parse Audit Score').first().json;

// Schedule at noon today (IST)
const scheduledAt = (() => { const d = new Date(); d.setHours(12, 0, 0, 0); return Math.floor(d.getTime() / 1000); })();

return [{ json: {
  ...ctx,
  image_url: imageUrl,
  buffer_profile_id: ctx.brand === 'floatup' ? 'YOUR_FLOATUP_INSTAGRAM_BUFFER_PROFILE_ID' : 'YOUR_AI_COMMUNITY_INSTAGRAM_BUFFER_PROFILE_ID',
  buffer_scheduled_at: scheduledAt
}}];

const ctx = $input.first().json;

// Schedule LinkedIn at 8:30 AM (catches morning commute)
const scheduledAt = (() => { const d = new Date(); d.setHours(8, 30, 0, 0); return Math.floor(d.getTime() / 1000); })();

return [{ json: {
  ...ctx,
  image_url: '',
  buffer_profile_id: ctx.brand === 'floatup' ? 'YOUR_FLOATUP_LINKEDIN_BUFFER_PROFILE_ID' : 'YOUR_AI_COMMUNITY_LINKEDIN_BUFFER_PROFILE_ID',
  buffer_scheduled_at: scheduledAt
}}];

